import { gamepads, spud, Button, HapticIntensity } from '../src';

function gameLoop() {
  console.log(`there are ${spud.players} connected controllers`);

  // loop through only the connected gamepads
  gamepads.connectedPlayers.forEach((player) => {
    console.log(player.index, player.gamepadInfo.productName);
  });

  // or target just a specific player
  const isPlayer3PressingSelect = gamepads.p3.isButtonDown(Button.Select);

  // if p1 just pressed a the left dpad button
  if (gamepads.p1.buttonJustPressed(Button.DpadLeft)) {
    // provide 50ms of light haptic feedback
    gamepads.p1.rumble(50, HapticIntensity.Light);

    // and read player-specific settings from spud
    console.log(spud.p1.name, spud.p1.color);
  }

  // if all connected players are simultaneously pressing start
  if (gamepads.allPlayers.isButtonDown(Button.Start)) {
    // ...
  }

  // read current axis values
  const {
    // normalized x and y to account for deadzones
    x,
    y,
    // raw axis values from the gamepad
    rawX,
    rawY,
    // normalized x and y values that snap to 4-way or 8-way directions
    snap4,
    snap8,
  } = gamepads.p1.leftStick;

  // simplified access to trigger axes
  const { value, rawValue, rumble } = gamepads.p1.leftTrigger;

  // start a 100ms heavy haptic in p1's left trigger
  rumble(100, HapticIntensity.Heavy);

  // if any player just pressed the A or ✕ button...
  if (gamepads.anyPlayer.buttonJustPressed(Button.South)) {
    // ...
  }

  // you always have access to the raw Gamepad, so this:
  gamepads.p1.gamepad?.vibrationActuator.reset();
  // ...is the same as this:
  gamepads.p1.hapticReset();

  // call this function once, at the end of your update cycle, in order to save
  // a snapshot of the previous buttons down and other state. this is how we're
  // able to provide utilities like `buttonJustReleased` which compare current
  // and prior gamepad states.
  gamepads.clearInputs();

  // loop infinitely
  requestAnimationFrame(gameLoop);
}

gameLoop();

